# ❌ ANTI-PATTERN: Dynamic shapes breaking graph compilation
@tf.function
def predict_batsman_score(bowling_data):
    # PROBLEM: Input shape changes per call
    # Graph retraces every time, negating performance benefits
    x = tf.reshape(bowling_data, [-1, 10])
    return model(x)

# Variable batch sizes force recompilation
scores1 = predict_batsman_score(tf.random.normal([32, 10]))  # Traces
scores2 = predict_batsman_score(tf.random.normal([64, 10]))  # Retrace (expensive!)

# ✅ BEST PRACTICE: Static shapes with explicit input signatures
@tf.function(input_signature=[
    tf.TensorSpec(shape=[None, 10], dtype=tf.float32)  # Flexible batch, fixed features
])
def predict_batsman_score(bowling_data):
    # One trace for all batch sizes matching the signature
    x = tf.reshape(bowling_data, [-1, 10])
    return model(x)

# Both compile to same graph
scores1 = predict_batsman_score(tf.random.normal([32, 10]))  # Traces once
scores2 = predict_batsman_score(tf.random.normal([64, 10]))  # Reuses graph

# ❌ ANTI-PATTERN: Eager training without optimization
for epoch in range(100):
    for batch in dataset:
        loss = model(batch)  # Unoptimized, full python loop overhead

# ✅ BEST PRACTICE: Hybrid approach — graph inner loop, eager outer
@tf.function
def train_step(images, labels):
    with tf.GradientTape() as tape:
        predictions = model(images)
        loss = loss_fn(labels, predictions)
    gradients = tape.gradient(loss, model.trainable_variables)
    optimizer.apply_gradients(zip(gradients, model.trainable_variables))
    return loss

for epoch in range(100):
    for batch_images, batch_labels in dataset:
        loss = train_step(batch_images, batch_labels)  # Graphed, fast
        print(f"Loss: {loss.numpy()}")  # Eager inspection
